// R30 — Database helpers shared by store mutators.
//
// Two responsibilities:
//   1. Map the legacy in-memory user IDs (u-vp, u-mgr1, …) to the Postgres UUIDs
//      used in profiles.id (which are FK to auth.users.id). Same map is baked
//      into vite/migrations/r30_seed.sql so the FK references resolve.
//   2. Provide a fire-and-forget Supabase write wrapper so mutators stay
//      synchronous from React's POV (optimistic UI) while still persisting.

import { supabase, USE_SUPABASE } from './supabase.js';

// Stable UUIDs generated by vite/migrations/generate-seed.mjs (sha256-derived,
// so re-running the generator produces the same UUIDs on every machine).
// Source of truth: vite/migrations/uuid-map.json (kept identical to this map).
export const USER_UUID = {
  'u-vp':    '4c8e3a5b-7d2f-4b91-8a3c-1f6e9d8c7b5a',
  'u-mgr1':  'a1b2c3d4-e5f6-4789-9abc-def012345678',
  'u-mgr2':  'b2c3d4e5-f6a7-4890-bcde-f01234567890',
  'u-op1':   'c3d4e5f6-a7b8-4901-cdef-012345678901',
  'u-op2':   'd4e5f6a7-b8c9-4012-def0-123456789012',
  'u-pgm':   'e5f6a7b8-c9d0-4123-ef01-234567890123',
  'u-mat':   'f6a7b8c9-d0e1-4234-f012-345678901234',
  'u-coord': '07a8b9c0-d1e2-4345-8012-456789012345',
  'u-pm1':   '18b9c0d1-e2f3-4456-9123-567890123456',
  'u-pm2':   '29c0d1e2-f3a4-4567-a234-678901234567',
  'u-pm3':   '3ad1e2f3-a4b5-4678-b345-789012345678',
  'u-pm4':   '4be2f3a4-b5c6-4789-c456-890123456789',
  'u-pm5':   '5cf3a4b5-c6d7-489a-d567-90123456789a',
  'u-pm6':   '6da4b5c6-d7e8-49ab-e678-a12345678901',
  'u-pm7':   '7eb5c6d7-e8f9-4abc-f789-b23456789012',
};

export function userUuid(id) {
  if (!id) return null;
  if (USER_UUID[id]) return USER_UUID[id];
  // If we receive a real auth.users UUID (already in v4 form) pass it through.
  if (/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(id)) return id;
  return null;
}

// Reverse map: for incoming Supabase rows that carry profile UUIDs, find the
// legacy id the UI still uses (PEOPLE[].id). Falls through to UUID when no map.
const __REVERSE = Object.fromEntries(Object.entries(USER_UUID).map(([k, v]) => [v, k]));
export function legacyUserId(uuid) { return __REVERSE[uuid] || uuid; }

// Map R29 in-memory role names (e.g. 'Manager', 'Operations Manager') to the
// Postgres user_role enum values (snake_case).
export const ROLE_TO_ENUM = {
  'VP':                 'vp',
  'Manager':            'manager',
  'Operations Manager': 'operations_manager',
  'Program Manager':    'program_manager',
  'Project Manager':    'project_manager',
  'Material planning':  'material_planning',
  'Coordinator':        'coordinator',
};
export const ENUM_TO_ROLE = Object.fromEntries(Object.entries(ROLE_TO_ENUM).map(([k, v]) => [v, k]));

// Fire-and-forget Supabase writer. The store mutator updates React state
// synchronously (optimistic), and this scheduled write persists in the
// background. On failure, we log to console + emit a window event the
// shell can toast on.
//   bg(fn, label) — fn returns a thenable; label is for error messages.
export function bg(fn, label) {
  if (!USE_SUPABASE) return;
  Promise.resolve().then(fn).then(({ error } = {}) => {
    if (error) {
      console.error(`[supabase ${label}]`, error);
      if (typeof window !== 'undefined') {
        window.dispatchEvent(new CustomEvent('supabase-error', { detail: { label, error } }));
      }
    }
  }).catch(err => {
    console.error(`[supabase ${label}] threw`, err);
  });
}

// Convenience: insert one row, fire-and-forget.
export function bgInsert(table, row, label = table) {
  bg(() => supabase.from(table).insert(row), `insert ${label}`);
}
// Convenience: update by id.
export function bgUpdate(table, id, patch, label = table) {
  bg(() => supabase.from(table).update(patch).eq('id', id), `update ${label}`);
}
// Convenience: delete by id.
export function bgDelete(table, id, label = table) {
  bg(() => supabase.from(table).delete().eq('id', id), `delete ${label}`);
}
// Convenience: upsert (for app_settings).
export function bgUpsert(table, row, label = table) {
  bg(() => supabase.from(table).upsert(row), `upsert ${label}`);
}

if (typeof window !== 'undefined') {
  Object.assign(window, { USER_UUID, userUuid, legacyUserId, ROLE_TO_ENUM, ENUM_TO_ROLE, bg, bgInsert, bgUpdate, bgDelete, bgUpsert });
}
